interface SpaceDetailPanelProps {
  space: Space;
  usersInSpace: UserPresenceData[];
  agendaPhase?: { current: number; total: number; name: string; description?: string };
  activityLog?: ActivityLogEntry[];
  transcript?: { text: string; speaker: string; timestamp: Date };
  isUserInSpace: boolean;
  isPrivate?: boolean;
  onJoin: () => void;
  onLeave: () => void;
  onKnock?: () => void;
  onUserClick?: (userId: string) => void;
  onClose?: () => void;
  className?: string;
}

interface ActivityLogEntry {
  id: string;
  timestamp: Date;
  author: string;
  authorId: string;
  summary: string;
  type: 'decision' | 'action' | 'note' | 'blocker' | 'join' | 'leave';
}

function useSpaceDetails(spaceId: string | null): {
  agenda: { current: number; total: number; name: string } | null;
  activityLog: ActivityLogEntry[];
  transcript: { text: string; speaker: string; timestamp: Date } | null;
  isLoading: boolean;
  error: Error | null;
}

interface ParticipantRosterProps {
  users: UserPresenceData[];
  onUserClick?: (userId: string) => void;
  maxHeight?: number;
  speakingUserIds?: string[];
  presentingUserId?: string;
  mutedUserIds?: string[];
}

interface SpaceActionButtonsProps {
  isUserInSpace: boolean;
  isPrivate?: boolean;
  onJoin: () => void;
  onLeave: () => void;
  onKnock?: () => void;
}
